#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-17

# =============================================================================
# Orphan Rule File Detector
# =============================================================================
# Skills organise reference material under src/skills/{name}/rules/*.md and
# src/skills/{name}/references/*.md. These files are meant to be loaded on
# demand by the SKILL.md body. When a rule file isn't referenced anywhere,
# it becomes dead weight that still adds to the repo size and auditing cost.
#
# Detection: for each rules/*.md and references/*.md, grep the skill's
# SKILL.md body + rules/_sections.md for a mention. Flag unreferenced files.
#
# Advisory by default. Set ORPHAN_RULES_ENFORCE=1 to fail CI.
# =============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
SKILLS_DIR="$REPO_ROOT/src/skills"

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

ENFORCE="${ORPHAN_RULES_ENFORCE:-0}"

echo -e "${BLUE}${BOLD}Orphan rule/reference detector${NC}"

orphans=()
total_files=0

# Iterate every skill directory
for skill_md in "$SKILLS_DIR"/*/SKILL.md; do
    skill_dir="$(dirname "$skill_md")"
    skill_name="$(basename "$skill_dir")"

    # Companion files to search in
    sections="$skill_dir/rules/_sections.md"
    rule_content=""
    [[ -f "$skill_md" ]] && rule_content+=$(cat "$skill_md")
    [[ -f "$sections" ]] && rule_content+=$'\n'$(cat "$sections")

    # Check rules/*.md (skip _sections.md itself)
    for rule_file in "$skill_dir"/rules/*.md "$skill_dir"/references/*.md; do
        [[ -f "$rule_file" ]] || continue
        rule_base="$(basename "$rule_file")"
        [[ "$rule_base" == "_sections.md" ]] && continue

        total_files=$((total_files + 1))

        # Does the skill content reference this file?
        # Accept either the basename or the full relative path
        rule_stem="${rule_base%.md}"
        if grep -qE "(${rule_base}|${rule_stem})" <<<"$rule_content"; then
            continue
        fi

        orphans+=("$skill_name: $rule_file")
    done
done

echo ""
echo -e "  Scanned: ${total_files} rule/reference files across $(find "$SKILLS_DIR" -maxdepth 1 -mindepth 1 -type d | wc -l | tr -d ' ') skills"
echo ""

if [[ ${#orphans[@]} -eq 0 ]]; then
    echo -e "${GREEN}✓ All rule/reference files are referenced${NC}"
    exit 0
fi

echo -e "${YELLOW}⚠ ${#orphans[@]} orphan rule/reference file(s) — referenced nowhere:${NC}"
printf '  - %s\n' "${orphans[@]}" | head -40
if [[ ${#orphans[@]} -gt 40 ]]; then
    echo -e "  ... and $(( ${#orphans[@]} - 40 )) more"
fi
echo ""
echo -e "${BLUE}To fix:${NC} either reference the file from SKILL.md / _sections.md, or delete it."
echo ""

if [[ "$ENFORCE" == "1" ]]; then
    echo -e "${RED}✗ Enforcement on — failing.${NC}"
    exit 1
fi

echo -e "${YELLOW}(Advisory mode — not failing.)${NC}"
exit 0
